 import { Settlement } from '../models/settlement';
 import { EventBus } from '../events/bus';
+import { logger } from '../utils/logger';

 const PROCESSING_WINDOW_MS = 30 * 60 * 1000; // 30 minutes
+const GRACE_PERIOD_MS = 15 * 60 * 1000; // 15 minutes

@@ -18,3 +20,35 @@ export class SettlementService {
     return this.repo.findById(id);
   }
+
+  async checkTimeout(settlement: Settlement): Promise<SettlementTimeoutResult | null> {
+    const now = Date.now();
+    const age = now - new Date(settlement.createdAt).getTime();
+
+    if (settlement.status === 'warning') {
+      const warnedAt = new Date(settlement.warnedAt!).getTime();
+      if (now - warnedAt > GRACE_PERIOD_MS) {
+        await this.repo.update(settlement.id, { status: 'cancelled' });
+        this.eventBus.emit('settlement.cancelled', { settlementId: settlement.id });
+        logger.info('settlement auto-cancelled after grace period', { settlementId: settlement.id });
+        return {
+          settlementId: settlement.id,
+          status: 'cancelled',
+          triggeredAt: new Date().toISOString(),
+        };
+      }
+    }
+
+    if (age > PROCESSING_WINDOW_MS && settlement.status === 'processing') {
+      await this.repo.update(settlement.id, { status: 'warning' });
+      logger.info('settlement timeout warning issued', { settlementId: settlement.id });
+      return {
+        settlementId: settlement.id,
+        status: 'warning',
+        triggeredAt: new Date().toISOString(),
+      };
+    }
+
+    return null;
+  }
 }
diff --git a/src/services/settlement.test.ts b/src/services/settlement.test.ts
index b2c3d4e..f6a7b8c 100644
--- a/src/services/settlement.test.ts
+++ b/src/services/settlement.test.ts
@@ -1,5 +1,30 @@
 import { SettlementService } from './settlement';
+import { createMockSettlement, createMockRepo, createMockEventBus } from '../test-utils';

 describe('SettlementService', () => {
+  let service: SettlementService;
+  let mockRepo: ReturnType<typeof createMockRepo>;
+  let mockEventBus: ReturnType<typeof createMockEventBus>;
+
+  beforeEach(() => {
+    mockRepo = createMockRepo();
+    mockEventBus = createMockEventBus();
+    service = new SettlementService(mockRepo, mockEventBus);
+  });
+
+  describe('checkTimeout', () => {
+    it('shows timeout warning when settlement exceeds processing window', async () => {
+      const settlement = createMockSettlement({
+        status: 'processing',
+        createdAt: new Date(Date.now() - 31 * 60 * 1000).toISOString(), // 31 min ago
+      });
+
+      const result = await service.checkTimeout(settlement);
+
+      expect(result).not.toBeNull();
+      expect(result!.status).toBe('warning');
+      expect(mockRepo.update).toHaveBeenCalledWith(settlement.id, { status: 'warning' });
+    });
+  });
 });
